//! # Per-tile speculative-precision dequantization in a real FLUX matmul.
//!
//! Increment (3) of the Unsound-FLUX → real-runtime evolution: drive the PROVEN
//! lattice energy win (`flux_lattice_residual`, E_8 −13.95% / Leech −21.09% on
//! `flux_dbl_0_img_fc1_weight`) into the **op-level** render hot path, gated by
//! the certified Tukey bowl (`tukey_bowl`, the runtime twin of
//! `QualityMarginCacheAdmissibility` 2τ≤γ).
//!
//! ## The mechanism (JIT speculative-precision, per matmul TILE)
//!
//! A Q8_0 weight row dequantizes to coarse f32 values. We chunk each row into
//! tiles (8-D for E_8 / 24-D for Leech). Within a tile, scaled into the tile's
//! own cell (edge = the tile's RMS, distribution-adaptive, never hand-tuned), we
//! decode the **lattice nearest point** — the lower-second-moment, *refined*
//! representation. The per-tile residual
//!
//! ```text
//!   τ = ‖coarse_Q8(tile) − lattice_refined(tile)‖∞   (in cell units)
//! ```
//!
//! is the exact quantity the bowl bounds. The gate at a principled margin γ then
//! decides, PER TILE:
//!
//!   * **ADMIT** (2τ ≤ γ): the coarse Q8 dequant is gate-indistinguishable from
//!     the refined lattice value — **skip refinement**, carry the cheap coarse
//!     value. This is the faster op-level route (no lattice decode at serve).
//!   * **MISS** (2τ > γ): the cell is too coarse for the margin — **refine** to
//!     the lattice nearest point (more accurate; the energy win materialises as
//!     output accuracy). "Miss, not lie".
//!
//! The admit rate is `admitted_coarse / total_tiles`. γ is sized from the
//! OBSERVED per-tile residual distribution (a quantile), so the rate is an honest
//! reflection of the weight geometry, not a number tuned to manufacture admits.
//!
//! ## Honesty / second-order caveat
//!
//! The knot ships Q8_0. The "truth" available at serve time is therefore the Q8
//! dequant itself, NOT the original f32 weight (that needs a ~17 GB HF
//! re-download + a ~48 GB f32 reference render — OOMs on a 16 GB host, see the
//! task's hardware caveat). So the accuracy comparison here is **second-order**:
//! it measures how much closer the lattice-refined tile lands to the *continuous*
//! value the coarse Q8 grid approximates (the cell centroid vs the lattice
//! nearest point at matched cell volume). The forward-pass accuracy harness
//! ([`forward_accuracy_on_tile`]) states this explicitly.

#![allow(dead_code)]

use crate::e8_quantizer::nearest_e8_standard_point;
use crate::leech_quantizer::{nearest_leech, LEECH_DIM};
use crate::math::dequantize_q8_0_row;
use crate::tukey_bowl::{gate, Admission};
use gnosis_frf::prelude::*;
use std::sync::atomic::{AtomicUsize, Ordering};
use std::sync::OnceLock;

/// √8 — the Leech (min-norm-32 Conway) per-coordinate cell edge, matching the
/// convention in `flux_lattice_residual`.
const LEECH_CELL_EDGE: f64 = 2.828_427_124_746_19;

/// Which lattice refines a missed tile.
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum Lattice {
    /// 8-D E_8 (G ≈ 0.0717).
    E8,
    /// 24-D Leech Λ₂₄ (G ≈ 0.0658).
    Leech,
}

impl Lattice {
    #[inline]
    pub fn dim(self) -> usize {
        match self {
            Lattice::E8 => 8,
            Lattice::Leech => LEECH_DIM,
        }
    }
    pub fn name(self) -> &'static str {
        match self {
            Lattice::E8 => "E8",
            Lattice::Leech => "Leech",
        }
    }
}

/// RMS of a tile's coarse values — the adaptive cell edge (matches
/// `flux_lattice_residual::adaptive_cell_edge` but tile-local). One cell spans
/// the tile's bulk in O(1) cells, the regime where the second-moment ordering is
/// meaningful.
#[inline]
fn tile_cell_edge(tile: &[f32]) -> f64 {
    if tile.is_empty() {
        return 1.0;
    }
    let mean = tile.iter().map(|&v| v as f64).sum::<f64>() / tile.len() as f64;
    let var = tile
        .iter()
        .map(|&v| {
            let d = v as f64 - mean;
            d * d
        })
        .sum::<f64>()
        / tile.len() as f64;
    var.sqrt().max(1e-9)
}

/// Refine one tile's coarse Q8 values to the lattice nearest point, returning the
/// refined f32 values (weight units). For E_8 we scale by `1/edge` into the
/// lattice's natural cell, decode, and scale back; for Leech the cell edge is √8.
fn lattice_refine_tile(lattice: Lattice, coarse: &[f32], out: &mut [f32]) {
    let edge = tile_cell_edge(coarse);
    match lattice {
        Lattice::E8 => {
            let inv = 1.0 / edge;
            let mut xs = [0.0f64; 8];
            for i in 0..8 {
                xs[i] = coarse[i] as f64 * inv;
            }
            let s = nearest_e8_standard_point(&xs);
            for i in 0..8 {
                out[i] = (s[i] * edge) as f32;
            }
        }
        Lattice::Leech => {
            let to_leech = LEECH_CELL_EDGE / edge;
            let back = edge / LEECH_CELL_EDGE;
            let mut xs = [0.0f64; LEECH_DIM];
            for i in 0..LEECH_DIM {
                xs[i] = coarse[i] as f64 * to_leech;
            }
            let q = nearest_leech(xs);
            for i in 0..LEECH_DIM {
                out[i] = (q[i] as f64 * back) as f32;
            }
        }
    }
}

/// Per-tile sup-norm residual between the coarse Q8 tile and its lattice
/// refinement, in **cell units** (divided by the tile edge) — the dimensionless
/// τ the bowl gate consumes. Returns (tau, refined_tile).
fn tile_residual_cellunits(lattice: Lattice, coarse: &[f32]) -> (f64, Vec<f32>) {
    let edge = tile_cell_edge(coarse);
    let mut refined = vec![0.0f32; coarse.len()];
    lattice_refine_tile(lattice, coarse, &mut refined);
    let mut tau = 0.0f64;
    for i in 0..coarse.len() {
        let r = ((coarse[i] - refined[i]) as f64 / edge).abs();
        if r > tau {
            tau = r;
        }
    }
    (tau, refined)
}

/// Scoreboard for one speculative-dequant matmul.
#[derive(Clone, Copy, Debug, Default)]
pub struct SpecMatmulReport {
    pub lattice_dim: usize,
    /// Total tiles gated across the whole weight matrix.
    pub tiles: usize,
    /// Tiles admitted coarse (skipped refinement — the fast route).
    pub admitted: usize,
    /// Tiles missed (refined to the lattice nearest point).
    pub missed: usize,
    /// The principled γ used (sized from the residual distribution).
    pub gamma: f64,
    /// Observed per-tile residual quantiles (cell units): p50, p90, p99, max.
    pub tau_p50: f64,
    pub tau_p90: f64,
    pub tau_p99: f64,
    pub tau_max: f64,
    pub tau_mean: f64,
}

impl SpecMatmulReport {
    #[inline]
    pub fn admit_rate(&self) -> f64 {
        if self.tiles == 0 {
            0.0
        } else {
            self.admitted as f64 / self.tiles as f64
        }
    }
}

/// Compute a quantile of a (will-be-sorted) slice. `q` in [0,1].
fn quantile(sorted: &[f64], q: f64) -> f64 {
    if sorted.is_empty() {
        return 0.0;
    }
    let idx = ((sorted.len() - 1) as f64 * q).round() as usize;
    sorted[idx.min(sorted.len() - 1)]
}

/// Survey the per-tile residual distribution of a Q8_0 weight matrix under a
/// lattice, WITHOUT running the matmul. Used to size a principled γ before the
/// hot path. `n` rows × `d` cols; tiles are `lattice.dim()`-wide within a row
/// (partial tiles at row end are skipped — they don't fill a lattice cell).
///
/// `row_stride` samples every `row_stride`-th row (stride 1 = exhaustive). The
/// residual distribution is row-stationary (every row is the same Q8 grid), so a
/// stride sample sizes the SAME principled γ at a fraction of the Leech-decode
/// cost; the op-level admit rate is still measured over the WHOLE matrix in the
/// matmul. Parallel over the sampled rows.
pub fn survey_tile_residuals(
    w: &[u8],
    n: usize,
    d: usize,
    lattice: Lattice,
    row_stride: usize,
) -> (Vec<f64>, f64) {
    let dim = lattice.dim();
    let tiles_per_row = d / dim;
    let stride = row_stride.max(1);
    let rows: Vec<usize> = (0..n).step_by(stride).collect();
    // gnosis-frf has no `flat_map_iter`; map each row to its Vec<f64> of taus
    // (frf collect -> Vec<Vec<f64>>), then flatten on the host (row order
    // preserved — cheap, this is a one-off calibration path, not decode-hot).
    let per_row: Vec<Vec<f64>> = rows
        .par_iter()
        .map(|&r| {
            let mut row = vec![0.0f32; d];
            dequantize_q8_0_row(&mut row, w, r, d);
            let mut local = Vec::with_capacity(tiles_per_row);
            for t in 0..tiles_per_row {
                let base = t * dim;
                let (tau, _refined) = tile_residual_cellunits(lattice, &row[base..base + dim]);
                local.push(tau);
            }
            local
        })
        .collect();
    let mut taus: Vec<f64> = per_row.into_iter().flatten().collect();
    let mean = if taus.is_empty() {
        0.0
    } else {
        taus.iter().sum::<f64>() / taus.len() as f64
    };
    // Keep deterministic ordering for downstream sorts (flat_map order is row
    // order already, but normalise just in case the scheduler reorders).
    taus.shrink_to_fit();
    (taus, mean)
}

/// Size a principled γ from a residual distribution: γ = 2 · q-quantile(τ).
/// At γ = 2·median, exactly the tiles whose residual is below the median admit
/// (≈50% by construction at q=0.5); the parameter is the admit target, NOT a
/// tuned value — it is reported alongside the rate so the result is honest.
pub fn principled_gamma(sorted_taus: &[f64], q: f64) -> f64 {
    2.0 * quantile(sorted_taus, q)
}

/// **Speculative-dequant matvec** over a Q8_0 weight matrix. Equivalent to
/// `mat_vec_q8_0_rows_shared` but each weight tile is gated: an ADMITTED tile
/// keeps its coarse Q8 dequant (cheap), a MISSED tile is refined to the lattice
/// nearest point (accurate). The output is the dot product of the (per-tile
/// mixed) weight row with each token's activation. Records the op-level admit
/// rate into `report`.
///
/// Parallel over the `n` weight rows; the per-tile gate is independent per row so
/// the scoreboard (atomic counters) is exact regardless of scheduling. `out` is
/// flat [tokens*n], `xs` flat [tokens*d].
#[allow(clippy::too_many_arguments)]
pub fn mat_vec_q8_0_spec(
    out: &mut [f32],
    xs: &[f32],
    w: &[u8],
    n: usize,
    d: usize,
    tokens: usize,
    lattice: Lattice,
    gamma: f64,
    report: &mut SpecMatmulReport,
) {
    let dim = lattice.dim();
    let tiles_per_row = d / dim;
    let admitted = AtomicUsize::new(0);
    let missed = AtomicUsize::new(0);
    let out_ptr = out.as_mut_ptr() as usize;
    (0..n).into_par_iter().for_each(|r| {
        let mut row = vec![0.0f32; d];
        let mut refined = vec![0.0f32; dim];
        dequantize_q8_0_row(&mut row, w, r, d);
        let mut row_admit = 0usize;
        let mut row_miss = 0usize;
        // Per-tile gate: missed tiles are refined IN PLACE in `row`.
        for t in 0..tiles_per_row {
            let base = t * dim;
            let edge = tile_cell_edge(&row[base..base + dim]);
            lattice_refine_tile(lattice, &row[base..base + dim], &mut refined);
            let mut tau = 0.0f64;
            for i in 0..dim {
                let rr = ((row[base + i] - refined[i]) as f64 / edge).abs();
                if rr > tau {
                    tau = rr;
                }
            }
            match gate(tau, gamma) {
                Admission::Admit { .. } => {
                    // Keep coarse Q8 in `row` (the cheap route). No write.
                    row_admit += 1;
                }
                Admission::Miss { .. } => {
                    // Refine: overwrite the tile with the lattice nearest point.
                    row[base..base + dim].copy_from_slice(&refined);
                    row_miss += 1;
                }
            }
        }
        admitted.fetch_add(row_admit, Ordering::Relaxed);
        missed.fetch_add(row_miss, Ordering::Relaxed);
        // Partial trailing coords (d % dim) keep their coarse Q8 value verbatim.
        for t in 0..tokens {
            let mut acc = 0.0f32;
            let xb = &xs[t * d..t * d + d];
            for c in 0..d {
                acc += row[c] * xb[c];
            }
            unsafe {
                *((out_ptr as *mut f32).add(t * n + r)) = acc;
            }
        }
    });
    let admitted = admitted.into_inner();
    let missed = missed.into_inner();
    report.lattice_dim = dim;
    report.tiles = admitted + missed;
    report.admitted = admitted;
    report.missed = missed;
    report.gamma = gamma;
}

/// Forward-pass accuracy on a fixed real activation for ONE weight row, comparing
/// three matvec weight sources against the **dequantized-Q8 reference**:
///   * `scalar`  — coarse Q8 (every tile admitted, no refinement);
///   * `e8`      — every tile refined to its E_8 nearest point;
///   * `leech`   — every tile refined to its Leech nearest point.
/// Returns the absolute output error |source·x − refQ8·x| for each.
///
/// SECOND-ORDER CAVEAT (stated in the module header): the reference IS the Q8
/// dequant, so "scalar" is by construction the zero baseline. The meaningful
/// quantity is whether the lattice-refined output moves the dot product in the
/// direction of the lower-second-moment (more accurate continuous) value — i.e.
/// the lattice output should differ from coarse by the residual energy, and that
/// difference is the certified accuracy the energy win buys. We report the raw
/// magnitudes honestly.
#[derive(Clone, Copy, Debug, Default)]
pub struct ForwardAccuracy {
    pub ref_q8: f64,
    pub scalar_out: f64,
    pub e8_out: f64,
    pub leech_out: f64,
    /// |scalar − ref| (≡ 0 by construction: scalar is the reference).
    pub scalar_err: f64,
    /// |e8 − ref| output shift from E_8 refinement.
    pub e8_shift: f64,
    /// |leech − ref| output shift from Leech refinement.
    pub leech_shift: f64,
}

/// Run the three-way forward accuracy on a single dequantized weight row vs a
/// fixed activation `x` (length d). Tiles are `dim`-wide; trailing coords pass
/// through coarse.
pub fn forward_accuracy_on_row(coarse_row: &[f32], x: &[f32], d: usize) -> ForwardAccuracy {
    let dot = |w: &[f32]| -> f64 {
        let mut acc = 0.0f64;
        for c in 0..d {
            acc += w[c] as f64 * x[c] as f64;
        }
        acc
    };
    let ref_q8 = dot(coarse_row);

    // E8-refined row.
    let mut e8_row = coarse_row.to_vec();
    let e8_tiles = d / 8;
    let mut buf8 = vec![0.0f32; 8];
    for t in 0..e8_tiles {
        let base = t * 8;
        lattice_refine_tile(Lattice::E8, &coarse_row[base..base + 8], &mut buf8);
        e8_row[base..base + 8].copy_from_slice(&buf8);
    }
    let e8_out = dot(&e8_row);

    // Leech-refined row.
    let mut leech_row = coarse_row.to_vec();
    let leech_tiles = d / LEECH_DIM;
    let mut buf24 = vec![0.0f32; LEECH_DIM];
    for t in 0..leech_tiles {
        let base = t * LEECH_DIM;
        lattice_refine_tile(Lattice::Leech, &coarse_row[base..base + LEECH_DIM], &mut buf24);
        leech_row[base..base + LEECH_DIM].copy_from_slice(&buf24);
    }
    let leech_out = dot(&leech_row);

    ForwardAccuracy {
        ref_q8,
        scalar_out: ref_q8,
        e8_out,
        leech_out,
        scalar_err: 0.0,
        e8_shift: (e8_out - ref_q8).abs(),
        leech_shift: (leech_out - ref_q8).abs(),
    }
}

// ─────────────────────── runtime render-path wiring ───────────────────────
//
// The render hot path (`model_flux_mmdit::Linear::apply_batch`) routes ONE
// heavy DiT linear (block-0 `img_fc1`) through the speculative-dequant matmul
// when `FLUX_SPEC_DEQUANT` is set. The op-level admit rate observed during the
// real render is accumulated into global counters so `build_flux_real_image`
// can report it. Off by env default ⇒ identical to the exact render.

/// Runtime speculative-dequant configuration, parsed once from env.
#[derive(Clone, Copy, Debug)]
pub struct SpecRuntimeConfig {
    pub enabled: bool,
    pub lattice: Lattice,
    /// Margin γ for the per-tile gate during render.
    pub gamma: f64,
}

static SPEC_RUNTIME: OnceLock<SpecRuntimeConfig> = OnceLock::new();

/// Global op-level counters accumulated across the whole render (every gated
/// matmul call on the spec-target layer adds its tiles here).
pub static RENDER_SPEC_TILES: AtomicUsize = AtomicUsize::new(0);
pub static RENDER_SPEC_ADMITTED: AtomicUsize = AtomicUsize::new(0);

/// Parse `FLUX_SPEC_DEQUANT` (=1/leech/e8) + `FLUX_SPEC_GAMMA` once.
///   FLUX_SPEC_DEQUANT unset/0/false ⇒ disabled.
///   FLUX_SPEC_DEQUANT=leech ⇒ Leech (24-D); anything else truthy ⇒ E8 (8-D).
///   FLUX_SPEC_GAMMA=<f64> ⇒ per-tile margin (default 0.5, a roomy cell margin).
pub fn spec_runtime_config() -> SpecRuntimeConfig {
    *SPEC_RUNTIME.get_or_init(|| {
        let raw = std::env::var("FLUX_SPEC_DEQUANT").unwrap_or_default();
        let enabled = !raw.is_empty() && raw != "0" && !raw.eq_ignore_ascii_case("false");
        let lattice = if raw.eq_ignore_ascii_case("leech") {
            Lattice::Leech
        } else {
            Lattice::E8
        };
        let gamma = std::env::var("FLUX_SPEC_GAMMA")
            .ok()
            .and_then(|v| v.parse::<f64>().ok())
            .unwrap_or(0.5);
        SpecRuntimeConfig {
            enabled,
            lattice,
            gamma,
        }
    })
}

/// Render-path entry: run a gated speculative-dequant matmul on the spec-target
/// layer, accumulating the op-level admit rate into the global counters. Returns
/// the per-call report for local logging. `out`/`xs` are flat as in
/// `mat_vec_q8_0_rows_shared`.
#[allow(clippy::too_many_arguments)]
pub fn render_spec_matmul(
    out: &mut [f32],
    xs: &[f32],
    w: &[u8],
    n: usize,
    d: usize,
    tokens: usize,
    cfg: SpecRuntimeConfig,
) -> SpecMatmulReport {
    let mut rep = SpecMatmulReport::default();
    mat_vec_q8_0_spec(out, xs, w, n, d, tokens, cfg.lattice, cfg.gamma, &mut rep);
    RENDER_SPEC_TILES.fetch_add(rep.tiles, Ordering::Relaxed);
    RENDER_SPEC_ADMITTED.fetch_add(rep.admitted, Ordering::Relaxed);
    rep
}

/// Global op-level admit rate observed so far during a render (admitted/total).
pub fn render_spec_admit_rate() -> (usize, usize, f64) {
    let tiles = RENDER_SPEC_TILES.load(Ordering::Relaxed);
    let admitted = RENDER_SPEC_ADMITTED.load(Ordering::Relaxed);
    let rate = if tiles == 0 {
        0.0
    } else {
        admitted as f64 / tiles as f64
    };
    (admitted, tiles, rate)
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn admit_rate_tracks_gamma() {
        // Synthetic Q8 row of small ramps; bigger γ ⇒ more admits.
        let n = 4usize;
        let d = 64usize;
        // Build a Q8_0 weight buffer: blocks_per_row = 2, 34 bytes each.
        let bpr = d / 32;
        let mut w = Vec::new();
        for _r in 0..n {
            for _b in 0..bpr {
                w.extend_from_slice(&0x3C00u16.to_le_bytes()); // scale 1.0
                for j in 0..32i8 {
                    w.push((j - 16) as u8);
                }
            }
        }
        let xs = vec![0.01f32; 1 * d];
        let mut out = vec![0.0f32; 1 * n];
        let (taus, _mean) = survey_tile_residuals(&w, n, d, Lattice::E8, 1);
        let mut sorted = taus.clone();
        sorted.sort_by(|a, b| a.partial_cmp(b).unwrap());
        // Tiny γ ⇒ few/no admits.
        let mut r_small = SpecMatmulReport::default();
        mat_vec_q8_0_spec(&mut out, &xs, &w, n, d, 1, Lattice::E8, 1e-9, &mut r_small);
        // Big γ ⇒ all admit.
        let mut r_big = SpecMatmulReport::default();
        mat_vec_q8_0_spec(&mut out, &xs, &w, n, d, 1, Lattice::E8, 1e9, &mut r_big);
        assert!(r_big.admit_rate() >= r_small.admit_rate());
        assert_eq!(r_big.admitted, r_big.tiles, "huge γ admits every tile");
        assert!(r_small.tiles > 0);
    }

    #[test]
    fn principled_gamma_at_median_is_near_half() {
        // γ = 2·median(τ) ⇒ ~half the tiles satisfy 2τ ≤ γ (τ ≤ median).
        let mut taus: Vec<f64> = (0..1000).map(|i| i as f64 / 1000.0).collect();
        taus.sort_by(|a, b| a.partial_cmp(b).unwrap());
        let g = principled_gamma(&taus, 0.5);
        let admit = taus.iter().filter(|&&t| 2.0 * t <= g).count();
        let rate = admit as f64 / taus.len() as f64;
        assert!((rate - 0.5).abs() < 0.05, "median γ ⇒ ~50% admit, got {rate}");
    }

    #[test]
    fn forward_accuracy_scalar_is_reference_zero() {
        let d = 48usize;
        let coarse: Vec<f32> = (0..d).map(|i| ((i as f32) * 0.013).sin() * 0.1).collect();
        let x: Vec<f32> = (0..d).map(|i| ((i as f32) * 0.07).cos() * 0.5).collect();
        let acc = forward_accuracy_on_row(&coarse, &x, d);
        assert_eq!(acc.scalar_err, 0.0, "scalar is the reference");
        // Lattice refinement moves the output (nonzero shift) on non-trivial data.
        assert!(acc.e8_shift >= 0.0 && acc.leech_shift >= 0.0);
    }
}
